import{_ as a,o as t,c as s,ai as n}from"./chunks/framework.DG6aArJf.js";const u=JSON.parse('{"title":"Module Dependencies — DOM Helpers JS","description":"","frontmatter":{},"headers":[],"relativePath":"MODULE-DEPENDENCIES.md","filePath":"MODULE-DEPENDENCIES.md"}'),o={name:"MODULE-DEPENDENCIES.md"};function i(r,e,d,l,h,p){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="module-dependencies-—-dom-helpers-js" tabindex="-1">Module Dependencies — DOM Helpers JS <a class="header-anchor" href="#module-dependencies-—-dom-helpers-js" aria-label="Permalink to “Module Dependencies — DOM Helpers JS”">​</a></h1><blockquote><p><strong>Who this page is for:</strong> complete beginners who have never used this library before. No prior experience required. Every technical term is explained before it is used.</p></blockquote><hr><h2 id="what-is-a-dependency" tabindex="-1">What is a dependency? <a class="header-anchor" href="#what-is-a-dependency" aria-label="Permalink to “What is a dependency?”">​</a></h2><p>Before we talk about modules, let us explain one word: <strong>dependency</strong>.</p><p>A dependency is something a piece of software <em>needs in order to work</em>.</p><p>Think of it like making a sandwich. Before you can put filling between two slices of bread, you need the bread first. The filling <em>depends on</em> the bread. If you try to add the filling without the bread, nothing holds together.</p><p>In this library, some modules work on their own — they are their own bread. Others only work <em>after</em> you have already loaded a different module. That first module is the dependency. Load it first, and everything works. Skip it, and the module that needs it cannot do its job.</p><hr><h2 id="the-modules-at-a-glance" tabindex="-1">The modules at a glance <a class="header-anchor" href="#the-modules-at-a-glance" aria-label="Permalink to “The modules at a glance”">​</a></h2><p>DOM Helpers JS is split into <strong>11 modules</strong> (plus a full bundle that includes them all, and a <strong>Module Loader</strong> that handles dependency resolution for you automatically).</p><p>Each module does one focused job. You only load the ones you need. Smaller pages load faster — every kilobyte counts.</p><p>Here is a quick summary before we go deeper:</p><table tabindex="0"><thead><tr><th>Module</th><th>What it does</th><th>Needs</th><th>Size (gzipped)</th></tr></thead><tbody><tr><td><strong>Full Bundle</strong></td><td>Everything in one file</td><td>Nothing — standalone</td><td>~49.7 KB</td></tr><tr><td><strong>Loader</strong></td><td>Loads modules on demand, resolves deps automatically</td><td>Nothing — standalone</td><td>~1 KB</td></tr><tr><td><strong>Core</strong></td><td>The foundation — selects and works with page elements</td><td>Nothing — standalone</td><td>~9.6 KB</td></tr><tr><td><strong>Storage</strong></td><td>Saves and reads data in the browser</td><td>Nothing — standalone</td><td>~1.3 KB</td></tr><tr><td><strong>SPA Router</strong></td><td>Handles page navigation without full reloads</td><td>Nothing — standalone</td><td>~3.9 KB</td></tr><tr><td><strong>Enhancers</strong></td><td>Adds bulk and shortcut operations to Core</td><td>Core</td><td>~8.4 KB</td></tr><tr><td><strong>Reactive</strong></td><td>Adds live, auto-updating state to your page</td><td>Core</td><td>~11.5 KB</td></tr><tr><td><strong>Form</strong></td><td>Reads, validates, and submits HTML forms</td><td>Core</td><td>~6.5 KB</td></tr><tr><td><strong>Animation</strong></td><td>Fades, slides, transforms, and chains animations</td><td>Core</td><td>~4.8 KB</td></tr><tr><td><strong>Async</strong></td><td>Debounce, throttle, fetch helpers, timers</td><td>Core</td><td>~3.9 KB</td></tr><tr><td><strong>Conditions</strong></td><td>Shows and hides elements based on rules</td><td>Core (+ Reactive recommended)</td><td>~7.2 KB</td></tr><tr><td><strong>Native Enhance</strong></td><td>Makes browser built-in selectors return enhanced elements</td><td>Core + Enhancers</td><td>~2.2 KB</td></tr></tbody></table><hr><h2 id="group-1-—-standalone-modules" tabindex="-1">Group 1 — Standalone modules <a class="header-anchor" href="#group-1-—-standalone-modules" aria-label="Permalink to “Group 1 — Standalone modules”">​</a></h2><p>These modules have <strong>no dependencies</strong>. Load them in any order, by themselves, and they just work.</p><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><p>Core is the starting point for almost everything else in the library. It gives you four tools — <code>Elements</code>, <code>Collections</code>, <code>Selector</code>, and <code>createElement</code> — that let you find, read, and change things on your web page.</p><p>If you are only loading one module, this is the one. If you load any other module (except Storage, SPA Router, or the Full Bundle), you must load Core first.</p><p><strong>Size:</strong> ~9.6 KB gzipped.</p><hr><h3 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to “Storage”">​</a></h3><p>Storage lets you save data in the browser so it persists even after the user closes the tab. It supports auto-save, watching for changes, and keeping data organised under named groups (called namespaces).</p><p>It has no connection to Core and no connection to any other module. You can use it entirely on its own.</p><p><strong>Size:</strong> ~1.3 KB gzipped.</p><hr><h3 id="spa-router" tabindex="-1">SPA Router <a class="header-anchor" href="#spa-router" aria-label="Permalink to “SPA Router”">​</a></h3><p>SPA stands for <em>Single-Page Application</em> — a website where clicking a link changes what is shown on screen without doing a full page reload. The SPA Router module handles that navigation: it watches the browser address bar, reads the path, and calls the right part of your code.</p><p>Like Storage, it is completely standalone. It does not need Core to function.</p><p><strong>Size:</strong> ~3.9 KB gzipped.</p><hr><h2 id="group-2-—-modules-that-need-core" tabindex="-1">Group 2 — Modules that need Core <a class="header-anchor" href="#group-2-—-modules-that-need-core" aria-label="Permalink to “Group 2 — Modules that need Core”">​</a></h2><p>These modules extend what Core can do. They <strong>must be loaded after Core</strong>. Think of them as extra tools that only make sense once you have the foundation in place.</p><h3 id="enhancers" tabindex="-1">Enhancers <a class="header-anchor" href="#enhancers" aria-label="Permalink to “Enhancers”">​</a></h3><p>Enhancers adds a wide set of shortcut and bulk-update operations to the <code>Elements</code>, <code>Collections</code>, and <code>Selector</code> objects that Core gives you. Instead of changing one element at a time, you can update dozens in a single call.</p><p>Enhancers does not add any new named objects — it quietly expands the ones Core already gave you. The same references just gain extra abilities.</p><p><strong>Needs:</strong> Core.</p><p><strong>Size:</strong> ~8.4 KB gzipped.</p><hr><h3 id="reactive" tabindex="-1">Reactive <a class="header-anchor" href="#reactive" aria-label="Permalink to “Reactive”">​</a></h3><p>Reactive adds <em>live state</em> to your page. A live state is a value that, when it changes, automatically updates every part of the page that depends on it — without you writing any extra code to keep things in sync.</p><p>Reactive also bundles its own built-in versions of async helpers, form handling, and storage — versions that are state-aware and integrate directly with reactive data. See the special note below for what this means in practice.</p><p><strong>Needs:</strong> Core.</p><p><strong>Size:</strong> ~11.5 KB gzipped.</p><hr><h3 id="form" tabindex="-1">Form <a class="header-anchor" href="#form" aria-label="Permalink to “Form”">​</a></h3><p>Form gives you a clean way to read values out of HTML forms, validate what the user typed, and submit data. It wraps the browser&#39;s built-in form behaviour in a more convenient interface.</p><p>This is the <em>non-reactive</em> version. It works independently. If you are already using the Reactive module, you do not need to load this separately — Reactive already includes a more powerful, state-aware form handler.</p><p><strong>Needs:</strong> Core.</p><p><strong>Size:</strong> ~6.5 KB gzipped.</p><hr><h3 id="animation" tabindex="-1">Animation <a class="header-anchor" href="#animation" aria-label="Permalink to “Animation”">​</a></h3><p>Animation gives you ready-made effects: fade in, fade out, slide up, slide down, slide toggle, transforms, and chains of animations that play one after another. It includes 30 different easing curves (the mathematical shapes that control how fast or slow an animation moves at each point).</p><p><strong>Needs:</strong> Core.</p><p><strong>Size:</strong> ~4.8 KB gzipped.</p><hr><h3 id="async" tabindex="-1">Async <a class="header-anchor" href="#async" aria-label="Permalink to “Async”">​</a></h3><p>Async provides helpers for timing-sensitive and network-related tasks. Debounce delays a function so it only fires after the user stops typing (useful for search inputs). Throttle limits how often a function can run. It also includes a smarter version of <code>fetch</code> for loading data from a server, plus utilities like <code>sleep</code>, <code>parallelAll</code>, and <code>raceWithTimeout</code>.</p><p>This is the <em>non-reactive</em> version. If you are using the Reactive module, you do not need this separately — Reactive already includes its own state-aware async helpers.</p><p><strong>Needs:</strong> Core.</p><p><strong>Size:</strong> ~3.9 KB gzipped.</p><hr><h2 id="group-3-—-modules-that-need-core-and-a-parent-module" tabindex="-1">Group 3 — Modules that need Core and a parent module <a class="header-anchor" href="#group-3-—-modules-that-need-core-and-a-parent-module" aria-label="Permalink to “Group 3 — Modules that need Core and a parent module”">​</a></h2><p>These modules sit at the end of the chain. They need more than just Core before they can be loaded.</p><h3 id="conditions" tabindex="-1">Conditions <a class="header-anchor" href="#conditions" aria-label="Permalink to “Conditions”">​</a></h3><p>Conditions lets you show and hide elements on the page based on rules you define — for example, show a warning panel only when a certain value is true, or hide a button unless a condition is met.</p><p>Conditions works on its own with just Core, but it gains a much more powerful mode when the Reactive module is also present. In that mode, it can watch live state and update the page automatically whenever a rule&#39;s outcome changes. Loading Reactive before Conditions turns this extra mode on.</p><p><strong>Needs:</strong> Core. Reactive is strongly recommended for full functionality.</p><p><strong>Size:</strong> ~7.2 KB gzipped.</p><hr><h3 id="native-enhance" tabindex="-1">Native Enhance <a class="header-anchor" href="#native-enhance" aria-label="Permalink to “Native Enhance”">​</a></h3><p>Native Enhance patches the browser&#39;s own element-selection methods — <code>getElementById</code>, <code>getElementsBy*</code>, <code>querySelector</code>, and <code>querySelectorAll</code> — so they return enhanced elements instead of plain browser elements. After loading this module, you get the library&#39;s full set of helpers on <em>any</em> element you select, even using the browser&#39;s built-in functions.</p><p>This module needs both Core and Enhancers to be loaded first, because it patches those already-enhanced objects into the native methods.</p><p><strong>Needs:</strong> Core + Enhancers.</p><p><strong>Size:</strong> ~2.2 KB gzipped.</p><hr><h2 id="special-case-—-the-reactive-module" tabindex="-1">Special case — The Reactive module <a class="header-anchor" href="#special-case-—-the-reactive-module" aria-label="Permalink to “Special case — The Reactive module”">​</a></h2><p>The Reactive module behaves differently depending on what else is loaded alongside it. This is worth understanding before you decide what to include.</p><h3 id="reactive-already-includes-async-form-and-storage" tabindex="-1">Reactive already includes Async, Form, and Storage <a class="header-anchor" href="#reactive-already-includes-async-form-and-storage" aria-label="Permalink to “Reactive already includes Async, Form, and Storage”">​</a></h3><p>When you load Reactive, you automatically get reactive-aware versions of async helpers, form handling, and storage. These built-in versions are more capable than the standalone modules — they can track changes and stay in sync with your reactive state.</p><p>This means:</p><ul><li>If you are using Reactive and need form handling, <strong>do not load the Form module separately</strong> — Reactive already covers it.</li><li>If you are using Reactive and need storage, <strong>do not load Storage separately</strong> — Reactive already covers it.</li><li>If you are using Reactive and need async helpers, <strong>do not load Async separately</strong> — Reactive already covers it.</li></ul><p>Only load the standalone Form, Storage, or Async modules if you are <em>not</em> using Reactive.</p><table tabindex="0"><thead><tr><th>What you want</th><th>Use Reactive?</th><th>Load Form / Storage / Async separately?</th></tr></thead><tbody><tr><td>Form handling, no live state</td><td>No</td><td>Yes — load Form module</td></tr><tr><td>Storage, no live state</td><td>No</td><td>Yes — load Storage module</td></tr><tr><td>Async helpers, no live state</td><td>No</td><td>Yes — load Async module</td></tr><tr><td>All of the above, with live state</td><td>Yes</td><td>No — already included in Reactive</td></tr></tbody></table><h3 id="no-problem-if-you-load-both" tabindex="-1">No problem if you load both <a class="header-anchor" href="#no-problem-if-you-load-both" aria-label="Permalink to “No problem if you load both”">​</a></h3><p>If your project already loads the standalone Form, Storage, or Async modules alongside Reactive, nothing breaks. The library detects the situation and handles it automatically. Both sets load and run correctly — the reactive versions simply take over in reactive contexts.</p><h3 id="conditions-gets-a-power-up-from-reactive" tabindex="-1">Conditions gets a power-up from Reactive <a class="header-anchor" href="#conditions-gets-a-power-up-from-reactive" aria-label="Permalink to “Conditions gets a power-up from Reactive”">​</a></h3><p>As mentioned above, loading Reactive before Conditions gives Conditions access to live state. It can then watch reactive values and update the page automatically when rules change. If Reactive is not present, Conditions still works — it just evaluates rules once, at load time, rather than watching them continuously.</p><p><strong>Always load Reactive before Conditions</strong> to get the full reactive+static mode.</p><hr><h2 id="load-order-rule" tabindex="-1">Load order rule <a class="header-anchor" href="#load-order-rule" aria-label="Permalink to “Load order rule”">​</a></h2><p>When loading multiple modules manually, follow this order:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>1. Core            (always first, if you are using it)</span></span>
<span class="line"><span>2. Storage         (can go anywhere — no dependencies)</span></span>
<span class="line"><span>3. SPA Router      (can go anywhere — no dependencies)</span></span>
<span class="line"><span>4. Enhancers       (after Core)</span></span>
<span class="line"><span>5. Reactive        (after Core, and before Conditions)</span></span>
<span class="line"><span>6. Form            (after Core — skip if using Reactive)</span></span>
<span class="line"><span>7. Animation       (after Core)</span></span>
<span class="line"><span>8. Async           (after Core — skip if using Reactive)</span></span>
<span class="line"><span>9. Conditions      (after Core, ideally after Reactive)</span></span>
<span class="line"><span>10. Native Enhance (after Core + Enhancers)</span></span></code></pre></div><p>You do not need to load every module — only the ones your project actually uses. The order above applies to whichever subset you choose.</p><p><strong>Two shortcuts:</strong></p><ul><li>If you need most features, load the <strong>Full Bundle</strong> — one file, everything included, no ordering to think about.</li><li>If you want a specific subset, use the <strong>Module Loader</strong> — it resolves the order automatically:<div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> load</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;reactive&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;native-enhance&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;animation&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// → loads: core → enhancers → reactive → animation → native-enhance</span></span></code></pre></div></li></ul><hr><h2 id="the-module-loader" tabindex="-1">The Module Loader <a class="header-anchor" href="#the-module-loader" aria-label="Permalink to “The Module Loader”">​</a></h2><p>The loader (<code>dom-helpers.loader.esm.min.js</code> / <code>dom-helpers.loader.min.js</code>) is a tiny utility (~1 KB gzipped) that takes care of the dependency chain for you. Instead of writing multiple <code>&lt;script&gt;</code> tags in the right order, you call <code>load()</code> with the modules you want:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ESM — type=&quot;module&quot; environments</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { load } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://cdn.jsdelivr.net/npm/dom-helpers-js@2.10.0/dist/dom-helpers.loader.esm.min.js&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">await</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> load</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;reactive&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;conditions&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;native-enhance&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// loads: core → enhancers → reactive → conditions → native-enhance (correct order, automatically)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Classic — plain &lt;script&gt; tags</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DOMHelpersLoader.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">load</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;reactive&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;conditions&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;native-enhance&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">then</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // all modules ready on window</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">});</span></span></code></pre></div><p><strong>Rules that the loader enforces for you:</strong></p><ul><li>Core is always loaded before any module that needs it</li><li>Enhancers is loaded before Native Enhance</li><li>Reactive is loaded before Conditions when both are requested</li><li>Already-loaded modules (by any means) are silently skipped — never fetched twice</li><li>Argument order in <code>load()</code> does not matter — the correct sequence is resolved from the graph</li></ul><p>See <a href="./module-loader.html">module-loader.md</a> for the full API and usage patterns.</p><hr><h2 id="dependency-map" tabindex="-1">Dependency map <a class="header-anchor" href="#dependency-map" aria-label="Permalink to “Dependency map”">​</a></h2><p>Here is a visual summary showing which modules depend on which:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Core  ────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>  │                                                           │</span></span>
<span class="line"><span>  ├── Enhancers ──────── Native Enhance (needs Core + Enhancers)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── Reactive ─────────────────────────────────┐</span></span>
<span class="line"><span>  │                                             │</span></span>
<span class="line"><span>  ├── Conditions (works alone; better with Reactive)</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├── Form</span></span>
<span class="line"><span>  ├── Animation</span></span>
<span class="line"><span>  └── Async</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Storage     (standalone — no connection to Core)</span></span>
<span class="line"><span>SPA Router  (standalone — no connection to Core)</span></span></code></pre></div><hr><p><em>This page covers module loading and dependencies only. For usage examples and API details, see the main README. For loader patterns and API, see <a href="./module-loader.html">module-loader.md</a>. For all CDN URLs, see <a href="./ALL-CDN-LINKS.html">ALL-CDN-LINKS.md</a>.</em></p>`,110)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
